executeFunc((function productReviewReadmore(){const textBlocks=document.querySelectorAll(".textBlock");const toggleBtns=document.querySelectorAll(".toggleBtn");textBlocks.forEach(((textBlock,index)=>{const toggleBtn=toggleBtns[index];const btnText=toggleBtn.querySelector("span");let isExpanded=false;let animationFrame=null;const ROW_COUNT=1;const ANIMATION_DURATION=300;const LINE_HEIGHT=parseFloat(getComputedStyle(textBlock).lineHeight)||24;const COLLAPSED_HEIGHT=LINE_HEIGHT*ROW_COUNT;function checkHeight(){const originalClass=textBlock.className;textBlock.classList.remove("truncated-text");textBlock.classList.add("expanded-text");const fullHeight=textBlock.scrollHeight;textBlock.classList.remove("expanded-text");textBlock.classList.add("truncated-text");const textBlockText=textBlock.innerHTML;if(textBlockText.length<150){toggleBtn.classList.add("d-none");textBlock.classList.add("expanded-text");textBlock.classList.remove("truncated-text")}else{toggleBtn.classList.remove("d-none")}}function animateHeight(startHeight,endHeight,callback){const startTime=performance.now();textBlock.classList.remove("truncated-text","expanded-text");textBlock.style.overflow="hidden";textBlock.style.display="-webkit-box";textBlock.style.webkitBoxOrient="vertical";function update(currentTime){const elapsed=currentTime-startTime;const progress=Math.min(elapsed/ANIMATION_DURATION,1);const easeProgress=progress<.5?2*progress*progress:1-Math.pow(-2*progress+2,2)/2;const currentHeight=startHeight+(endHeight-startHeight)*easeProgress;textBlock.style.height=currentHeight+"px";if(progress<1){animationFrame=requestAnimationFrame(update)}else{textBlock.style.height="";textBlock.style.overflow="";textBlock.style.display="";textBlock.style.webkitBoxOrient="";if(endHeight>COLLAPSED_HEIGHT){textBlock.classList.add("expanded-text")}else{textBlock.classList.add("truncated-text")}if(callback){callback()}animationFrame=null}}animationFrame=requestAnimationFrame(update)}function toggleText(){if(animationFrame){cancelAnimationFrame(animationFrame);animationFrame=null}const currentHeight=textBlock.scrollHeight;if(!isExpanded){textBlock.classList.remove("truncated-text");textBlock.classList.add("expanded-text");const fullHeight=textBlock.scrollHeight;textBlock.classList.remove("expanded-text");textBlock.classList.add("truncated-text");animateHeight(COLLAPSED_HEIGHT,fullHeight,(()=>{btnText.textContent="Свернуть";toggleBtn.classList.add("rotated")}))}else{animateHeight(currentHeight,COLLAPSED_HEIGHT,(()=>{btnText.textContent="Читать полностью";toggleBtn.classList.remove("rotated")}))}isExpanded=!isExpanded}checkHeight();toggleBtn.addEventListener("click",toggleText)}));return true}));